public String play(Gesture[] user) {
        int win = 0, lose = 0;
        for (int i = 0; i < 3; i++) {
            sysGesture[i] = generateGestureByRandom();
            if (user[i].equals("scissors")) {
                if (sysGesture[i].equals("PAPER")) {
                    win += 1;
                }
                if (sysGesture[i].equals("STONE")) {
                    lose += 1;
                }
                if (sysGesture[i].equals("SCISSORS")) {
                    //win = win;
                    //lose = lose;
                }
            } else if (user[i].equals("paper")) {
                if (sysGesture[i].equals("STONE")) {
                    win += 1;
                }
                if (sysGesture[i].equals("SCISSORS")) {
                    lose += 1;
                }
                if (sysGesture[i].equals("PAPER")) {
                    win = win;
                    lose = lose;
                }
            }else if (user[i].equals("stone")) {
                if (sysGesture[i].equals("SCISSORS")) {
                    win += 1;
                }
                if (sysGesture[i].equals("PAPER")) {
                    lose += 1;
                }
                if (sysGesture[i].equals("STONE")) {
                    win = win;
                    lose = lose;
                }
            }
        }
你應該是用使用者輸入去判斷win and lose 的條件，加油。

